import{_ as r,o as a,c as o,a2 as p}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"猜涨跌","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/predict-market.md","filePath":"zh-CN/rewards/predict-market.md"}'),e={name:"rewards/predict-market.md"};function i(l,t,d,n,s,h){return a(),o("div",null,[...t[0]||(t[0]=[p('<h1 id="猜涨跌" tabindex="-1">猜涨跌 <a class="header-anchor" href="#猜涨跌" aria-label="Permalink to &quot;猜涨跌&quot;">​</a></h1><p>猜涨跌是 App 内的股票价格预测迷你游戏。用户消耗任务币参与，预测指定股票当天的涨跌方向或具体涨跌幅区间；预测正确可获得任务币奖励。同时参与猜涨跌还可以推进相关任务进度，帮助用户完成任务中心的对应任务。</p><h2 id="如何参与" tabindex="-1">如何参与 <a class="header-anchor" href="#如何参与" aria-label="Permalink to &quot;如何参与&quot;">​</a></h2><p>参与猜涨跌需已登录 App 账户，且账户内有足够的任务币余额。</p><p>操作步骤：</p><ol><li>进入猜涨跌游戏页面（从任务中心进入，或在社区帖子中点击猜涨跌卡片）</li><li>查看当前可参与的轮次和目标股票</li><li>选择下注的任务币数量</li><li>选择玩法：猜方向（选择&quot;涨&quot;或&quot;跌&quot;），或猜区间（从系统提供的涨跌幅区间段中选择一个）</li><li>可选：选择使用道具提升奖励倍数</li><li>确认提交，等待收盘后系统自动判断结果</li></ol><p>收盘后系统自动比对实际涨跌与用户预测，预测正确则自动发放任务币奖励至账户。再次进入猜涨跌页面时，若有上一轮获胜记录，系统会自动弹出获奖提示。可在历史记录页面查看每一轮的猜测结果和奖励明细。</p><h2 id="状态说明" tabindex="-1">状态说明 <a class="header-anchor" href="#状态说明" aria-label="Permalink to &quot;状态说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态名称</th><th>含义</th><th>用户应该做什么</th></tr></thead><tbody><tr><td>进行中</td><td>当前轮次开放，可以参与猜测</td><td>选择玩法并下注参与</td></tr><tr><td>已结束</td><td>本轮截止，等待收盘结果</td><td>等待系统自动判断结果并发放奖励</td></tr><tr><td>未开始</td><td>下一轮尚未开放</td><td>等待下一轮开放</td></tr></tbody></table><h2 id="参与规则与结算答疑" tabindex="-1">参与规则与结算答疑 <a class="header-anchor" href="#参与规则与结算答疑" aria-label="Permalink to &quot;参与规则与结算答疑&quot;">​</a></h2><p><strong>猜涨跌是什么游戏？</strong></p><p>猜涨跌是 App 内的股票涨跌预测迷你游戏。用户花费任务币下注，预测指定股票当天涨还是跌（或具体涨跌幅区间），预测正确后获得任务币奖励。</p><p><strong>怎么参与猜涨跌？</strong></p><p>进入猜涨跌页面，确认当前轮次处于&quot;进行中&quot;状态，选择下注任务币数量，再选择猜方向（涨/跌）或猜区间，提交后等待收盘即可。</p><p><strong>猜涨跌需要花费什么？</strong></p><p>参与需消耗任务币。任务币可通过完成任务中心的各类任务获得，不是现金。</p><p><strong>猜对了可以获得什么奖励？</strong></p><p>猜对后系统自动发放任务币奖励。具体奖励金额取决于下注数量和玩法类型。连续猜对还可获得额外奖励。</p><p><strong>猜涨跌每天什么时候开始和结束？</strong></p><p>开始和结束时间以当前轮次页面显示为准，受交易日和股票市场规则影响。非交易日（如节假日、休市日）可能没有猜涨跌活动。</p><p><strong>一天可以参与几次猜涨跌？</strong></p><p>参与次数以当前活动规则为准，具体限制请查看猜涨跌页面内的活动说明。</p><p><strong>&quot;猜区间&quot;和&quot;猜方向&quot;有什么区别？</strong></p><p>猜方向只需选择&quot;涨&quot;或&quot;跌&quot;，难度较低；猜区间（进阶模式）从系统提供的固定宽度涨跌幅区间中选择一个，难度更高但奖励倍数也更高。部分活动还支持使用道具进一步提升奖励倍数，道具可通过兑换商城获取。两种玩法可根据个人偏好选择。</p><p><strong>猜对后奖励多久到账？</strong></p><p>通常在收盘后系统完成结算时自动到账，一般当天内完成。如超过 24 小时未到账，可联系客服查询。</p><p><strong>历史猜涨跌记录在哪里看？</strong></p><p>在猜涨跌页面内有历史记录入口，可查看每一轮的参与情况、猜测结果和奖励明细。</p><p><strong>为什么今天没有猜涨跌活动？</strong></p><p>可能原因包括：今天是非交易日（节假日或市场休市）、本期活动已结束而下一期尚未开放、或当前账户不满足参与条件。可稍后刷新页面查看，或联系客服确认。</p><p><strong>连续猜对有额外奖励吗？</strong></p><p>有。连续猜对可触发连胜奖励机制，获得额外的任务币奖励。具体连胜奖励规则以活动页面说明为准。</p><p><strong>我的任务币被扣除了但看不到猜涨跌结果怎么办？</strong></p><p>可能是网络延迟或系统结算尚未完成。建议：等待几分钟后刷新页面；在历史记录中查找该轮次的结果；如仍无法查看，请联系客服并提供参与时间，客服会协助核查。</p><h2 id="道具消耗规则与合规要求" tabindex="-1">道具消耗规则与合规要求 <a class="header-anchor" href="#道具消耗规则与合规要求" aria-label="Permalink to &quot;道具消耗规则与合规要求&quot;">​</a></h2><ul><li>参与后不可撤销或更改预测，提交即生效</li><li>游戏结果以系统收盘价计算为准，与行情显示的实时价格可能有细微差异</li><li>任务币无法提现，仅可在平台内使用</li><li>非交易日不开放猜涨跌活动</li><li>参与猜涨跌可推进任务中心中&quot;参与猜涨跌 N 次&quot;等相关任务的进度</li><li>部分活动支持使用道具提升奖励，道具可通过兑换商城获取</li></ul>',36)])])}const q=r(e,[["render",i]]);export{c as __pageData,q as default};
